CREATE TABLE `app_virtual_device_pool` (`id` bigint AUTO_INCREMENT NOT NULL PRIMARY KEY, `device_id` bigint NOT NULL UNIQUE, `is_active` bool NOT NULL, `created_at` datetime(6) NOT NULL, `updated_at` datetime(6) NOT NULL);
CREATE TABLE `unified_notification_configs` (`id` bigint AUTO_INCREMENT NOT NULL PRIMARY KEY, `name` varchar(100) NOT NULL, `config_type` varchar(20) NOT NULL, `webhook_bots` json NULL, `is_default` bool NOT NULL, `is_active` bool NOT NULL, `created_at` datetime(6) NOT NULL, `updated_at` datetime(6) NOT NULL, `created_by_id` bigint NOT NULL);
CREATE TABLE `data_factory_record` (`id` bigint AUTO_INCREMENT NOT NULL PRIMARY KEY, `user_id` bigint NOT NULL, `tool_name` varchar(100) NOT NULL, `tool_category` varchar(20) NOT NULL, `tool_scenario` varchar(20) NOT NULL, `input_data` json NULL, `output_data` json NOT NULL, `is_saved` bool NOT NULL, `tags` json NULL, `created_at` datetime(6) NOT NULL, `updated_at` datetime(6) NOT NULL);
CREATE TABLE `performance_load_test_tasks` (`id` char(32) NOT NULL PRIMARY KEY, `name` varchar(200) NOT NULL, `test_type` varchar(20) NOT NULL, `target_url` varchar(500) NOT NULL, `concurrency` integer NOT NULL, `duration` integer NOT NULL, `ramp_up` integer NOT NULL, `status` varchar(20) NOT NULL, `peak_rps` double precision NOT NULL, `avg_response_time` double precision NOT NULL, `error_rate` double precision NOT NULL, `total_requests` integer NOT NULL, `result_summary` longtext NOT NULL, `report_file` varchar(100) NULL, `created_by_id` bigint NOT NULL, `created_at` datetime(6) NOT NULL, `started_at` datetime(6) NULL, `completed_at` datetime(6) NULL);
CREATE TABLE `security_scan_tasks` (`id` char(32) NOT NULL PRIMARY KEY, `name` varchar(200) NOT NULL, `scan_type` varchar(20) NOT NULL, `target` varchar(500) NOT NULL, `tool` varchar(50) NOT NULL, `depth` integer NOT NULL, `status` varchar(20) NOT NULL, `total_risks` integer NOT NULL, `high_risks` integer NOT NULL, `medium_risks` integer NOT NULL, `low_risks` integer NOT NULL, `result_summary` longtext NOT NULL, `report_file` varchar(100) NULL, `created_by_id` bigint NOT NULL, `created_at` datetime(6) NOT NULL, `started_at` datetime(6) NULL, `completed_at` datetime(6) NULL);
CREATE TABLE `security_findings` (`id` char(32) NOT NULL PRIMARY KEY, `task_id` char(32) NOT NULL, `title` varchar(300) NOT NULL, `detail` longtext NOT NULL, `severity` varchar(20) NOT NULL, `target` varchar(500) NOT NULL, `remediation` longtext NOT NULL, `created_at` datetime(6) NOT NULL);

CREATE TABLE `django_migrations` (
  `id` bigint NOT NULL AUTO_INCREMENT PRIMARY KEY,
  `app` varchar(255) NOT NULL,
  `name` varchar(255) NOT NULL,
  `applied` datetime(6) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
